const { PrismaClient } = require\('@prisma/client'\);
const p = new PrismaClient\(\);
p.moveAnalysis.findMany\({
  where: { gameId: 'cmncd7y4z0064ibvhwjacaw6j' },
  orderBy: { plyIndex: 'asc' }
}\).then\(moves => {
  const nullEval = moves.filter\(m => m.evalBefore === null\).length;
  const hasEval = moves.filter\(m => m.evalBefore !== null\).length;
  const sideWrong = moves.filter\(m => m.side === 'w'\).length;
  const sideRight = moves.filter\(m => m.side === 'b'\).length;
  console.log\('total moves:', moves.length\);
  console.log\('null evalBefore:', nullEval, '/ has evalBefore:', hasEval\);
  console.log\('side=w:', sideWrong, '/ side=b:', sideRight\);
  // show first move with evalBefore set if any
  const withEval = moves.find\(m => m.evalBefore !== null\);
  console.log\('first with eval:', withEval ? JSON.stringify\({plyIndex: withEval.plyIndex, evalBefore: withEval.evalBefore, evalLoss: withEval.evalLoss, classification: withEval.classification}\) : 'NONE'\);
  // show all classifications
  const classMap = {};
  moves.forEach\(m => { classMap[m.classification ?? 'null'] = \(classMap[m.classification ?? 'null'] || 0\) + 1; }\);
  console.log\('classifications:', classMap\);
}\).finally\(\(\) => p.\\$disconnect\(\)\);
